```jsx
import React, { Suspense, lazy } from 'react';

const ProductScreen = lazy(() =&gt; import('./ProductScreen'));

function App() {
  return (
    &lt;Suspense fallback={$\text{......}$}&gt;
      &lt;ProductScreen /&gt;
    &lt;/Suspense&gt;
  );
}
```
